it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
  const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
  expect(new Set(result.map(c => c.join(",")))).toEqual(
    new Set([[0, 0], [1, 0], [0, 1], [1, 1]].map(c => c.join(",")))
